/* Pseudocode: hybrid fanout worker */
function onTweetCreated(tweet) {
  followers = getFollowers(tweet.author)
  if (followers.count < PUSH_THRESHOLD) {
    // Fan-out on write: push into per-follower timelines
    batches = batch(followers, 1000)
    for (b of batches) enqueuePush(b, tweet)
  } else {
    // Too big: mark the tweet as "pull-on-read" and store in central TweetStore
    markForPullOnRead(tweet)
  }
}

// Reader: get timeline
function getTimeline(user) {
  if (cache.has(user.timeline)) return cache.get(user.timeline)
  timeline = readTimelineStore(user) // fast lookup for precomputed list
  if (!timeline) {
    // assemble by pulling recent tweets from followees (fallback path)
    timeline = assembleOnRead(user.following)
  }
  cache.set(user.timeline, timeline)
  return timeline
}
